import{_ as t,o as e,c as r,a1 as o}from"./chunks/framework.qq2wtA-j.js";const u=JSON.parse('{"title":"辅助脚本","description":"","frontmatter":{},"headers":[],"relativePath":"aegisub-automation/helper-scripts.md","filePath":"aegisub-automation/helper-scripts.md"}'),l={name:"aegisub-automation/helper-scripts.md"};function d(i,a,n,s,c,g){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="辅助脚本" tabindex="-1">辅助脚本 <a class="header-anchor" href="#辅助脚本" aria-label="Permalink to &quot;辅助脚本&quot;">​</a></h1><p>本目录下的 Lua 脚本用于 Aegisub 自动化，辅助 AMLL 歌词制作工作流。脚本需放置在 Aegisub 的 <code>automation/autoload/</code> 目录下。</p><p>所有脚本的 GitHub 源文件链接格式为 <code>https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/&lt;脚本名&gt;.lua</code>。</p><h2 id="标记与标签" tabindex="-1">标记与标签 <a class="header-anchor" href="#标记与标签" aria-label="Permalink to &quot;标记与标签&quot;">​</a></h2><h3 id="add-num-—-添加行编号" tabindex="-1">add-num — 添加行编号 <a class="header-anchor" href="#add-num-—-添加行编号" aria-label="Permalink to &quot;add-num — 添加行编号&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/add-num.lua" target="_blank" rel="noreferrer">add-num.lua</a></p><p>为所有 <code>orig</code> 行自动添加序号标记（<code>L_1</code>、<code>L_2</code> 等），写入到 <code>actor</code> 字段中。非 <code>orig</code> 行或背景行会被标记为 <code>____</code>。遇到 <code>x-chor</code> 标记时序号会自动 +2（为合唱行预留位置）。</p><p><strong>使用方法：</strong></p><ul><li>直接运行「Add line num - 添加行编号」宏，无需选中行</li><li>作用于整个字幕文件的所有行</li></ul><h3 id="add-tag-—-添加-ttml-标记" tabindex="-1">add-tag — 添加 TTML 标记 <a class="header-anchor" href="#add-tag-—-添加-ttml-标记" aria-label="Permalink to &quot;add-tag — 添加 TTML 标记&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/add-tag.lua" target="_blank" rel="noreferrer">add-tag.lua</a></p><p>为选中行的 <code>actor</code> 字段添加 TTML 标记。</p><p><strong>支持的标记：</strong></p><table tabindex="0"><thead><tr><th>标记</th><th>含义</th><th>适用行样式</th></tr></thead><tbody><tr><td><code>x-bg</code></td><td>背景和声</td><td>orig</td></tr><tr><td><code>x-duet</code></td><td>对唱</td><td>orig</td></tr><tr><td><code>x-solo</code></td><td>独唱</td><td>orig</td></tr><tr><td><code>x-anti</code></td><td>反声</td><td>orig</td></tr><tr><td><code>x-fade</code></td><td>淡入淡出</td><td>orig</td></tr><tr><td><code>x-whis</code></td><td>气声/耳语</td><td>orig</td></tr><tr><td><code>x-chor</code></td><td>合唱</td><td>orig</td></tr><tr><td><code>x-other</code></td><td>其它</td><td>orig</td></tr><tr><td><code>x-person</code></td><td>个人</td><td>orig</td></tr><tr><td><code>x-group</code></td><td>团体</td><td>orig</td></tr><tr><td><code>x-role</code></td><td>角色（需填值）</td><td>orig</td></tr><tr><td><code>x-lang</code></td><td>语言（需填值）</td><td>ts / roma</td></tr><tr><td><code>x-replace</code></td><td>替换标记</td><td>ts / roma</td></tr></tbody></table><p><strong>使用方法：</strong></p><ol><li>选中需要标记的行</li><li>运行「Add TTML Tag - 添加 TTML 标记」宏</li><li>在下拉框中选择标记类型</li><li>如需要（<code>x-lang</code>、<code>x-role</code> 等），填写对应的值</li></ol><h3 id="set-part-—-标记歌词部分" tabindex="-1">set-part — 标记歌词部分 <a class="header-anchor" href="#set-part-—-标记歌词部分" aria-label="Permalink to &quot;set-part — 标记歌词部分&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/set-part.lua" target="_blank" rel="noreferrer">set-part.lua</a></p><p>为选中行添加 <code>x-part</code> 标记，用于标注歌词的段落类型（主歌、副歌等）。</p><p><strong>支持的段落类型：</strong></p><ul><li>Verse（主歌）</li><li>Chorus（副歌）</li><li>PreChorus（预副歌）</li><li>Rise（短推）</li><li>Bridge（桥段）</li><li>Intro（前奏）</li><li>Outro（尾奏）</li><li>Refrain（叠句）</li><li>Instrumental（器乐）</li><li>Interlude（间奏）</li><li>Transition（过渡）</li><li>Hook（钩子）</li><li>Reprise（再现）</li><li>DevelopedChorus（发展副歌）</li><li>FalseChorus（伪副歌）</li><li>FinalChorus（最终副歌）</li></ul><p><strong>使用方法：</strong></p><ol><li>选中 <strong>1 行</strong> <code>orig</code> 样式且非 <code>x-bg</code> 的行</li><li>运行「Set Part - 标记歌词部分」宏</li><li>在下拉框中选择段落类型，点击 Set</li></ol><h3 id="set-role-—-设置角色" tabindex="-1">set-role — 设置角色 <a class="header-anchor" href="#set-role-—-设置角色" aria-label="Permalink to &quot;set-role — 设置角色&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/set-role.lua" target="_blank" rel="noreferrer">set-role.lua</a></p><p>分为两个子菜单：<strong>设置</strong>（配置角色列表）和<strong>标记</strong>（应用角色到选中行）。</p><p><strong>设置角色列表：</strong></p><ol><li>运行「Set Role/设置」</li><li>在输入框中填写角色名称，可点击「添加」增加条目、「删除」移除最后一个条目</li><li>点击「确认」保存列表</li></ol><p><strong>标记角色：</strong></p><ol><li>选中 <code>orig</code> 行</li><li>运行「Set Role/标记」</li><li>勾选要分配的角色（支持多选）</li><li>点击「确认」，<code>x-role:&quot;角色名&quot;</code> 将被写入 <code>actor</code> 字段</li></ol><h2 id="时间同步" tabindex="-1">时间同步 <a class="header-anchor" href="#时间同步" aria-label="Permalink to &quot;时间同步&quot;">​</a></h2><h3 id="auto-sync-time-—-自动逐字同步" tabindex="-1">auto-sync-time — 自动逐字同步 <a class="header-anchor" href="#auto-sync-time-—-自动逐字同步" aria-label="Permalink to &quot;auto-sync-time — 自动逐字同步&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/auto-sync-time.lua" target="_blank" rel="noreferrer">auto-sync-time.lua</a></p><p>根据 <code>orig</code> 行中的 <code>{\\k...}</code> 时间标签，自动将翻译行（<code>ts</code>）或罗马音行（<code>roma</code>）的文本按字符/音节拆分并同步对应的时间码。包含三个子功能：</p><ul><li><strong>auto sync translation</strong>：处理 <code>ts</code>（翻译）行，按字符逐个匹配 <code>\\k</code> 标签，适用于中文繁简体之间的逐字翻译</li><li><strong>auto sync translation/japan</strong>：处理 <code>roma</code>（罗马音）行，适用于日语，按假名音节拆分匹配</li><li><strong>auto sync translation/other</strong>：处理 <code>roma</code>（罗马音）行，通用模式，按空格分词匹配，适用于韩语、汉语等一字一音的语言</li></ul><p><strong>工作原理：</strong> 将翻译/音译行的文本逐词（或逐音节）替换原始 <code>\\k</code> 标签中的时间码，生成带时间的逐词歌词。原有的翻译/音译行会被注释掉，新生成的同步行会被插入。</p><p><strong>使用方法：</strong></p><ol><li>确保 <code>orig</code> 行已打好 <code>{\\k...}</code> 时间标签</li><li>确保紧跟在每个 <code>orig</code> 行之后有对应的 <code>ts</code> 或 <code>roma</code> 行</li><li>选中需要处理的区域</li><li>运行对应的子宏</li></ol><h2 id="导出与复制" tabindex="-1">导出与复制 <a class="header-anchor" href="#导出与复制" aria-label="Permalink to &quot;导出与复制&quot;">​</a></h2><h3 id="original-copy-—-复制原文" tabindex="-1">original-copy — 复制原文 <a class="header-anchor" href="#original-copy-—-复制原文" aria-label="Permalink to &quot;original-copy — 复制原文&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/original-copy.lua" target="_blank" rel="noreferrer">original-copy.lua</a></p><p>将选中行的原文（<code>orig</code> 样式）复制到系统剪贴板。支持添加行号和段落标记。</p><p><strong>使用方法：</strong></p><ol><li>选中需要复制的行</li><li>运行「copy original text - 复制原文」宏</li><li>选择「是」添加行号和 <code>x-part</code> 段落标记，或「否」仅复制纯文本</li><li>如剪贴板写入失败，会弹出文本框供手动复制</li></ol><h3 id="original-copy-all-—-复制所有原文" tabindex="-1">original-copy-all — 复制所有原文 <a class="header-anchor" href="#original-copy-all-—-复制所有原文" aria-label="Permalink to &quot;original-copy-all — 复制所有原文&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/original-copy-all.lua" target="_blank" rel="noreferrer">original-copy-all.lua</a></p><p>将所有选中行的 <code>text_stripped</code>（去除 ASS 标签后的纯文本）复制到剪贴板，不添加编号。</p><p><strong>使用方法：</strong></p><ol><li>选中行</li><li>运行「copy all original text - 复制所有原文」宏</li><li>若写入失败可手动复制</li></ol><h3 id="pure-amll-—-amll-歌词格式转换-纯文本" tabindex="-1">pure-amll — AMLL 歌词格式转换（纯文本） <a class="header-anchor" href="#pure-amll-—-amll-歌词格式转换-纯文本" aria-label="Permalink to &quot;pure-amll — AMLL 歌词格式转换（纯文本）&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/pure-amll.lua" target="_blank" rel="noreferrer">pure-amll.lua</a></p><p>将整个字幕文件中所有 <code>orig</code> 行转换为 AMLL TTML 格式的歌词并复制到剪贴板。TTML 中包含逐音节的时间标签（<code>&lt;span begin=&quot;...&quot; end=&quot;...&quot;&gt;</code>）。</p><p><strong>使用方法：</strong></p><ul><li>直接运行「Pure TTML - AMLL歌词格式转换(纯文本)」宏，无需选中行</li><li>生成的 TTML 会自动写入剪贴板</li></ul><h3 id="pure-sel-amll-—-amll-歌词格式转换-选中部分" tabindex="-1">pure-sel-amll — AMLL 歌词格式转换（选中部分） <a class="header-anchor" href="#pure-sel-amll-—-amll-歌词格式转换-选中部分" aria-label="Permalink to &quot;pure-sel-amll — AMLL 歌词格式转换（选中部分）&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/pure-sel-amll.lua" target="_blank" rel="noreferrer">pure-sel-amll.lua</a></p><p>与 <code>pure-amll</code> 功能相同，但仅转换选中的 <code>orig</code> 行。会校验选中的行是否合法（必须是 <code>orig</code> 样式且效果为空或 <code>karaoke</code>）。</p><p><strong>使用方法：</strong></p><ol><li>选中需要导出的 <code>orig</code> 行</li><li>运行「Pure TTML - AMLL歌词格式转换(选中部分)」宏</li><li>生成的 TTML 写入剪贴板</li></ol><h2 id="重置" tabindex="-1">重置 <a class="header-anchor" href="#重置" aria-label="Permalink to &quot;重置&quot;">​</a></h2><h3 id="reset-line-—-还原行内容" tabindex="-1">reset-line — 还原行内容 <a class="header-anchor" href="#reset-line-—-还原行内容" aria-label="Permalink to &quot;reset-line — 还原行内容&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/reset-line.lua" target="_blank" rel="noreferrer">reset-line.lua</a></p><p>一键还原字幕行的状态：</p><ul><li>删除所有 <code>effect</code> 为 <code>fx</code> 的行</li><li>将 <code>orig</code>、<code>ts</code>、<code>roma</code> 样式的行取消注释（恢复为非注释行）</li></ul><p>通常在完成时间同步或测试后使用，用于恢复到初始可编辑状态。</p><p><strong>使用方法：</strong></p><ul><li>直接运行「reset line - 还原行内容」宏，作用于整个字幕文件</li></ul>',67)])])}const p=t(l,[["render",d]]);export{u as __pageData,p as default};
